/* 文件头注释：使用树状数组统计区间内比某个数大的数的个数 */
#include <bits/stdc++.h>
using namespace std;

const int MAXN = 2e5 + 10;

int N;
int a[MAXN * 2];
int firstPos[MAXN];
int bit[MAXN * 2];

// 树状数组的更新操作
void update(int idx, int val) {
    while (idx <= 2 * N) {
        bit[idx] += val;
        idx += idx & -idx;
    }
}

// 树状数组的查询操作
int query(int idx) {
    int res = 0;
    while (idx > 0) {
        res += bit[idx];
        idx -= idx & -idx;
    }
    return res;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    cin >> N;
    for (int i = 1; i <= 2 * N; ++i) {
        cin >> a[i];
    }

    memset(firstPos, 0, sizeof(firstPos));
    memset(bit, 0, sizeof(bit));

    long long total = 0;

    for (int i = 1; i <= 2 * N; ++i) {
        if (firstPos[a[i]] == 0) {
            firstPos[a[i]] = i;
            update(i, 1); // 标记第一次出现的位置
        } else {
            int cnt = query(i) - query(firstPos[a[i]]);
            total += cnt;
            update(firstPos[a[i]], -1); // 移除第一次出现的位置
        }
    }

    cout << total << endl;

    return 0;
}

