/* 文件头注释：贪心算法，每次选择掌握程度最高的英雄进行特训 */
#include <bits/stdc++.h>
using namespace std;

int main() {
    int Y, M, L;
    cin >> Y >> M >> L;
    string result;
    int steps = 0;

    while (steps < 1000) {
        // 检查是否已经有两个英雄的掌握程度为0
        int zeroCount = 0;
        if (Y == 0) zeroCount++;
        if (M == 0) zeroCount++;
        if (L == 0) zeroCount++;
        if (zeroCount >= 2) {
            cout << result << endl;
            return 0;
        }

        // 选择当前掌握程度最高的英雄进行特训
        if (Y >= M && Y >= L) {
            result += 'Y';
            Y++;
            M--;
            L--;
        } else if (M >= Y && M >= L) {
            result += 'M';
            M++;
            Y--;
            L--;
        } else {
            result += 'L';
            L++;
            Y--;
            M--;
        }

        // 检查是否有英雄的掌握程度低于0
        if (Y < 0 || M < 0 || L < 0) {
            cout << "-1" << endl;
            return 0;
        }

        steps++;
    }

    // 如果超过1000次操作仍未达到目标，输出-1
    cout << "-1" << endl;
    return 0;
}

