/* 文件头注释：二分搜索结合贪心验证，确定最少厨师数量 */
#include <bits/stdc++.h>
using namespace std;

// 检查是否可以在K时间内用m个厨师完成所有任务
bool canComplete(int m, const vector<int>& a, int K) {
    priority_queue<int, vector<int>, greater<int>> pq; // 小根堆，存储每个厨师的可用时间
    for (int i = 0; i < m; ++i) {
        pq.push(0);
    }
    for (int time : a) {
        int earliest = pq.top();
        pq.pop();
        if (earliest + time > K) {
            return false;
        }
        pq.push(earliest + time);
    }
    return true;
}

int main() {
    int N, K;
    cin >> N >> K;
    vector<int> a(N);
    for (int i = 0; i < N; ++i) {
        cin >> a[i];
    }

    // 删除总时间判断逻辑，直接进行二分搜索
    int left = 1, right = N;
    while (left < right) {
        int mid = (left + right) / 2;
        if (canComplete(mid, a, K)) {
            right = mid;
        } else {
            left = mid + 1;
        }
    }

    // 检查最终结果是否满足条件
    if (canComplete(left, a, K)) {
        cout << left << endl;
    } else {
        cout << -1 << endl;
    }
    return 0;
}

