/* 文件头注释：改进的贪心算法，优先减少掌握程度较高的英雄的掌握程度 */
#include <bits/stdc++.h>
using namespace std;

int main() {
    int Y, M, L;
    cin >> Y >> M >> L;
    string result;
    int steps = 0;

    while (steps < 1000) {
        // 检查是否已经有两个英雄的掌握程度为0
        int zeroCount = 0;
        if (Y == 0) zeroCount++;
        if (M == 0) zeroCount++;
        if (L == 0) zeroCount++;
        if (zeroCount >= 2) {
            cout << result << endl;
            return 0;
        }

        // 计算每个英雄的掌握程度与其他英雄的差值
        int diffY = Y - M + Y - L;
        int diffM = M - Y + M - L;
        int diffL = L - Y + L - M;

        // 选择差值最大的英雄进行特训
        if (diffY >= diffM && diffY >= diffL) {
            result += 'Y';
            Y++;
            M--;
            L--;
        } else if (diffM >= diffY && diffM >= diffL) {
            result += 'M';
            M++;
            Y--;
            L--;
        } else {
            result += 'L';
            L++;
            Y--;
            M--;
        }

        // 检查是否有英雄的掌握程度低于0
        if (Y < 0 || M < 0 || L < 0) {
            cout << "-1" << endl;
            return 0;
        }

        steps++;
    }

    // 如果超过1000次操作仍未达到目标，输出-1
    cout << "-1" << endl;
    return 0;
}

