/* 文件头注释：动态规划解决组合数学问题 */
#include <bits/stdc++.h>
using namespace std;

const int MOD = 998244353;

// 快速幂函数，用于计算组合数
long long quick_pow(long long a, long long b) {
    long long res = 1;
    while (b) {
        if (b & 1) res = res * a % MOD;
        a = a * a % MOD;
        b >>= 1;
    }
    return res;
}

// 计算组合数C(n, k)
long long comb(int n, int k) {
    if (k > n) return 0;
    long long res = 1;
    for (int i = 1; i <= k; ++i) {
        res = res * (n - k + i) % MOD;
        res = res * quick_pow(i, MOD - 2) % MOD;
    }
    return res;
}

