/* 文件头注释：核心算法为检查2x2区域内的平衡条件 */
#include <bits/stdc++.h>
using namespace std;

int main() {
    int N, M;
    cin >> N >> M;
    vector<vector<int>> h(N, vector<int>(M));

    // 输入雪地高度
    for (int i = 0; i < N; ++i) {
        for (int j = 0; j < M; ++j) {
            cin >> h[i][j];
        }
    }

    // 计算整个矩阵的总和
    int total = 0;
    for (int i = 0; i < N; ++i) {
        for (int j = 0; j < M; ++j) {
            total += h[i][j];
        }
    }

    // 检查总和是否能够被N*M整除
    if (total % (N * M) != 0) {
        cout << "No" << endl;
        return 0;
    }

    // 检查所有2x2区域是否满足平衡条件
    bool possible = true;
    for (int i = 0; i < N - 1; ++i) {
        for (int j = 0; j < M - 1; ++j) {
            if (h[i][j] + h[i+1][j+1] != h[i][j+1] + h[i+1][j]) {
                possible = false;
                break;
            }
        }
        if (!possible) break;
    }

    // 输出结果
    if (possible) {
        cout << "Yes" << endl;
    } else {
        cout << "No" << endl;
    }

    return 0;
}

