/* 文件头注释：二分搜索结合贪心验证，确定最少厨师数量 */
#include <bits/stdc++.h>
using namespace std;

// 检查是否可以在K时间内用m个厨师完成所有任务
bool canComplete(int m, const vector<int>& a, int K) {
    vector<int> chefs(m, 0); // 记录每个厨师的可用时间
    for (int time : a) {
        // 找到最早可用的厨师
        auto it = lower_bound(chefs.begin(), chefs.end(), chefs[0]);
        int earliest = *it;
        if (earliest + time > K) {
            return false;
        }
        // 更新该厨师的可用时间
        *it += time;
        // 保持数组有序
        sort(chefs.begin(), chefs.end());
    }
    return true;
}

int main() {
    int N, K;
    cin >> N >> K;
    vector<int> a(N);
    for (int i = 0; i < N; ++i) {
        cin >> a[i];
    }

    // 删除总时间判断逻辑，直接进行二分搜索
    int left = 1, right = N;
    while (left < right) {
        int mid = (left + right) / 2;
        if (canComplete(mid, a, K)) {
            right = mid;
        } else {
            left = mid + 1;
        }
    }

    // 检查最终结果是否满足条件
    if (canComplete(left, a, K)) {
        cout << left << endl;
    } else {
        cout << -1 << endl;
    }
    return 0;
}

