    bool canFlatten = true;
    for (int i = 0; i < N - 1; ++i) {
        for (int j = 0; j < M - 1; ++j) {
            int sum1 = h[i][j] + h[i+1][j+1];
            int sum2 = h[i][j+1] + h[i+1][j];
            if (sum1 != sum2) {
                canFlatten = false;
                break;
