// 检查是否可以在给定时间内完成所有任务
bool canComplete(int N, int K, const vector<int>& a, int chefs) {
    int totalTime = 0;
    for (int i = 0; i < N; ++i) {
        if (a[i] > K) return false; // 单道菜时间超过K，无法完成
        if (totalTime + a[i] > K) {
            chefs--;
            totalTime = 0;
            if (chefs < 0) return false;
        }
        totalTime += a[i];
    }
    return true;
}

