        if (K == N) {
            long long sum = N * (N + 1) / 2;
            if (sum % N == 0) {
                cout << 1 << endl;
            } else {
                cout << 0 << endl;
            }
            continue;
        }

        // 动态规划数组
        vector<vector<long long>> dp(K + 1, vector<long long>(N, 0));
        dp[0][0] = 1;

        for (int i = 1; i <= K; ++i) {
            for (int j = 0; j < N; ++j) {
                for (int k = 0; k < N; ++k) {
                    int new_j = (j + k) % N;
                    dp[i][new_j] = (dp[i][new_j] + dp[i - 1][j]) % MOD;
                }
            }
        }

        cout << dp[K][0] << endl;
    }
